const html = $json.body || $json.data || '';
const text = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
return text;

const userInput = $('Extraer Datos').first().json.mensaje_usuario || 'No se pudo obtener el mensaje del usuario.';
const chatId = $('Extraer Datos').first().json.chat_id || '';
const userName = $('Extraer Datos').first().json.user_name || 'Usuario'; // Asume que 'user_name' viene de 'Extraer Datos'

// Intenta obtener la respuesta del bot de varias fuentes potenciales
let botResponse = '';

// Si viene de la rama FAQ (Preguntas FAQ -> Set3)
const set3Output = items.find(item => item.json && item.json.response);
if (set3Output) {
    botResponse = set3Output.json.response;
}

// Si viene de la rama de citas (Llamar envio de citas1 -> Merge2 -> ...)
// Aquí deberías buscar la respuesta final generada por tu subflujo de citas.
// Asumimos que el subflujo de citas o un nodo posterior en esa rama también expone una 'response'.
const citaOutput = items.find(item => item.json && item.json.response);
if (citaOutput && !botResponse) { // Solo si no se encontró ya una respuesta de FAQ
    botResponse = citaOutput.json.response;
}

// Si aún no se encontró una respuesta, usa un fallback
if (!botResponse) {
  botResponse = 'No se pudo obtener la respuesta final del bot.';
}

const timestamp = new Date().toISOString();

const logEntry = {
    timestamp: timestamp,
    chat_id: chatId,
    user_name: userName,
    user_input: userInput,
    bot_response: botResponse
};

return [ { json: logEntry } ];

const mensaje = $input.first().json.chatInput;
const chatId = $input.first().json.sessionId;

// Hora local de Madrid en formato ISO (YYYY-MM-DD HH:mm:ss)
const fechaMadrid = new Date().toLocaleString("sv-SE", { timeZone: "Europe/Madrid" }).replace(" ", "T");

return [
  {
    json: {
      mensaje_usuario: mensaje,
      chat_id: chatId,
      sessionId: chatId,
      timestamp: fechaMadrid
    }
  }
];

// 1) Marca de tiempo
const timestamp = new Date().toISOString();
// 2) Mismo chat ID que recibes en la petición
const chatId = $('Generar ID').first().json.sessionId|| $json.sessionId || $json["Chat ID"] || "";
// 3) Texto de la respuesta del bot (ajusta la propiedad según tu payload)
const botResponse = $input.first().json.output;

// 4) Devuelve el objeto con las mismas claves que tu hoja
return [{
  Timestap:      timestamp,    // coincide con tu columna "Timestap"
  "Chat ID":     chatId,       // con tu columna "Chat ID"
  "Bot Response": botResponse  // con tu columna "Bot Response"
}];

// Tomamos la respuesta
let raw = $json.Bot_response ?? '';

// Quitamos corchetes [ ] si viene como string tipo "[{...}]"
let text = String(raw).replace(/^\s*\[\s*|\s*\]\s*$/g, '');

// Quitamos únicamente las etiquetas HTML (ej. <b>...</b>)
text = text.replace(/<[^>]*>/g, '');

// Devolvemos el texto limpio de etiquetas
return [
  {
    json: { text }
  }
];

// Toma el input original
const input = $input.first().json;

// Genera un ID fijo
const sessionId = $input.first().json.sessionId ;

// Devuelve el objeto original más el campo sessionId fijo
return {
  ...input,
  sessionId,
};

